struct PromoData {
    let code: String
    let discount: Int
    let timestamp: Date
}

class UniversalLinkValidator {
    private static let allowedHosts = ["myapp.com", "www.myapp.com"]
    private static let allowedScheme = "https"
    private static let allowedPath = "/promo"
    
    static func isValidPromoLink(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              scheme == allowedScheme else {
            return false
        }
        
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            return false
        }
        
        guard url.path == allowedPath else {
            return false
        }
        
        return true
    }
}

class PromoLinkParser {
    static func parse(_ url: URL) -> PromoData? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return nil
        }
        
        var code: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                code = item.value
            case "discount":
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            default:
                break
            }
        }
        
        guard let promoCode = code, let discountValue = discount else {
            return nil
        }
        
        return PromoData(code: promoCode, discount: discountValue, timestamp: Date())
    }
}

class PromoDataValidator {
    static func validate(_ promoData: PromoData) -> String? {
        if !isValidPromoCode(promoData.code) {
            return "Invalid promo code format"
        }
        
        if !isValidDiscount(promoData.discount) {
            return "Invalid discount value"
        }
        
        return nil
    }
    
    private static func isValidPromoCode(_ code: String) -> Bool {
        let trimmedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard trimmedCode.count >= 3 && trimmedCode.count <= 20 else {
            return false
        }
        
        let allowedCharacterSet = CharacterSet.alphanumerics
        guard trimmedCode.unicodeScalars.allSatisfy({ allowedCharacterSet.contains($0) }) else {
            return false
        }
        
        return true
    }
    
    private static func isValidDiscount(_ discount: Int) -> Bool {
        return discount > 0 && discount <= 100
    }
}

class PromoService {
    static let shared = PromoService()
    private let userDefaults = UserDefaults.standard
    private let appliedPromosKey = "appliedPromos"
    private let currentPromoKey = "currentPromo"
    
    private init() {}
    
    func applyPromotion(_ promoData: PromoData, completion: @escaping (Result<Void, PromoError>) -> Void) {
        if hasPromoBeenApplied(promoData.code) {
            completion(.failure(.alreadyApplied))
            return
        }
        
        validatePromoWithServer(promoData) { result in
            switch result {
            case .success:
                self.saveAppliedPromo(promoData)
                self.setCurrentPromo(promoData)
                completion(.success(()))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    private func validatePromoWithServer(_ promoData: PromoData, completion: @escaping (Result<Void, PromoError>) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            completion(.success(()))
        }
    }
    
    private func hasPromoBeenApplied(_ code: String) -> Bool {
        let appliedPromos = userDefaults.stringArray(forKey: appliedPromosKey) ?? []
        return appliedPromos.contains(code)
    }
    
    private func saveAppliedPromo(_ promoData: PromoData) {
        var appliedPromos = userDefaults.stringArray(forKey: appliedPromosKey) ?? []
        appliedPromos.append(promoData.code)
        userDefaults.set(appliedPromos, forKey: appliedPromosKey)
    }
    
    private func setCurrentPromo(_ promoData: PromoData) {
        let promoDict: [String: Any] = [
            "code": promoData.code,
            "discount": promoData.discount,
            "timestamp": promoData.timestamp.timeIntervalSince1970
        ]
        userDefaults.set(promoDict, forKey: currentPromoKey)
    }
    
    func getCurrentPromo() -> PromoData? {
        guard let promoDict = userDefaults.dictionary(forKey: currentPromoKey),
              let code = promoDict["code"] as? String,
              let discount = promoDict["discount"] as? Int,
              let timestamp = promoDict["timestamp"] as? TimeInterval else {
            return nil
        }
        
        return PromoData(code: code, discount: discount, timestamp: Date(timeIntervalSince1970: timestamp))
    }
    
    func clearCurrentPromo() {
        userDefaults.removeObject(forKey: currentPromoKey)
    }
}

enum PromoError: Error {
    case alreadyApplied
    case invalidCode
    case expired
    case serverError
    
    var localizedDescription: String {
        switch self {
        case .alreadyApplied:
            return "This promo code has already been applied"
        case .invalidCode:
            return "Invalid promo code"
        case .expired:
            return "This promo code has expired"
        case .serverError:
            return "Unable to apply promo code. Please try again later"
        }
    }
}

